    /// <summary>All tags expected to be present on static sidebar items.
    /// Used by tests to assert catalog completeness.</summary>
    public static IReadOnlyCollection<string> KnownTags => s_resourceKey.Keys;

    /// <summary>Looks up the colorful SVG resource key for a sidebar tag.</summary>
    public static bool TryGetResourceKey(string? tag, out string resourceKey)
    {
        if (tag != null && s_resourceKey.TryGetValue(tag, out var key))
        {
            resourceKey = key;
            return true;
        }
        resourceKey = string.Empty;
        return false;
    }

    /// <summary>Looks up the SVG path-data string for the Mono variant of a
    /// sidebar tag. For dynamic <c>agent:*</c> tags, returns the shared
    /// <see cref="AgentsGroupPathData"/>.</summary>
    public static bool TryGetMonoPathData(string? tag, out string pathData)
    {
        if (tag != null)
        {
            if (s_monoPathData.TryGetValue(tag, out var p))
            {
                pathData = p;
                return true;
            }
            if (tag.StartsWith("agent:", StringComparison.Ordinal))
            {
                pathData = AgentsGroupPathData;
                return true;
            }
        }
        pathData = string.Empty;
        return false;
    }
